const transcript = $input.first().json.transcript_text;
const filename = $input.first().json.filename || 'unknown';
return [{ json: { transcript, filename, received_at: new Date().toISOString() } }];

const raw = $input.first().json.choices[0].message.content;
const clean = raw.replace(/```json|```/g, '').trim();
const start = clean.indexOf('{');
const end = clean.lastIndexOf('}') + 1;
const memo = JSON.parse(clean.slice(start, end));
memo.version = 'v1';
memo.extracted_at = new Date().toISOString();
return [{ json: memo }];

const memo = $input.first().json;
const company = memo.company_name || 'the company';
const hours = memo.business_hours || {};
const routing = memo.emergency_routing_rules || {};
const transfer = memo.call_transfer_rules || {};
const emergencies = (memo.emergency_definition || []).map(e => '  - ' + e).join('\n');
const special = (memo.special_instructions || []).map(s => '- ' + s).join('\n');

const systemPrompt = `You are a professional AI phone receptionist for ${company}.\n\nNEVER mention you are an AI or reference function calls. Speak naturally.\n\n## BUSINESS HOURS\n${hours.days || 'Mon-Fri'} ${hours.start || '8AM'} - ${hours.end || '5PM'} ${hours.timezone || ''}\n\n## BUSINESS HOURS FLOW\n1. Greet caller, state company name\n2. Ask for their name\n3. Understand the issue\n4. Collect callback number\n5. Transfer to team\n6. If transfer fails: ${transfer.fail_action || 'Take a message, promise callback'}\n7. Confirm next steps, ask if anything else, close warmly\n\n## AFTER HOURS FLOW\n1. State office is closed\n2. Ask if emergency or general inquiry\n3. EMERGENCIES are:\n${emergencies}\n4. If emergency: collect name, number, address immediately\n5. Attempt transfer to on-call team\n6. If transfer fails: ${routing.fallback_action || 'Take message, promise 30min callback'}\n7. Assure quick followup\n\n## RULES\n- Never mention function calls or transfers by name\n- Always get callback number before ending call\n- Do not ask more than 3 questions before helping`;

const spec = {
  agent_name: company + ' AI Receptionist',
  version: 'v1',
  generated_at: new Date().toISOString(),
  voice_style: { gender: 'female', tone: 'professional and warm', speed: 'normal' },
  system_prompt: systemPrompt,
  key_variables: {
    company_name: company,
    timezone: hours.timezone,
    business_hours: hours,
    office_address: memo.office_address,
    emergency_contacts: routing
  },
  call_transfer_protocol: {
    wait_seconds: transfer.wait_seconds || 30,
    transfer_order: [routing.primary, routing.secondary, routing.tertiary].filter(Boolean),
    on_fail: transfer.fail_action
  },
  fallback_protocol: {
    action: 'Take message',
    fields: ['name', 'callback_number', 'issue', 'address'],
    promise: '30 min callback for emergencies, next business day for non-emergencies'
  }
};

return [{ json: { memo, agent_spec: spec, account_id: memo.account_id } }];

const data = $input.first().json;
const fs = require('fs');
const path = require('path');
const accountId = data.account_id || 'unknown';
const dir = path.join('/data/outputs/accounts', accountId, 'v1');
fs.mkdirSync(dir, { recursive: true });
fs.writeFileSync(path.join(dir, 'account_memo.json'), JSON.stringify(data.memo, null, 2));
fs.writeFileSync(path.join(dir, 'agent_spec.json'), JSON.stringify(data.agent_spec, null, 2));
return [{ json: { account_id: accountId, status: 'saved', output_dir: dir } }];

const input = $input.first().json;
const fs = require('fs');
const path = require('path');
const accountId = input.account_id;
const memoPath = path.join('/data/outputs/accounts', accountId, 'v1', 'account_memo.json');
if (!fs.existsSync(memoPath)) throw new Error('No v1 memo found for: ' + accountId);
const existing = JSON.parse(fs.readFileSync(memoPath, 'utf8'));
return [{ json: { transcript: input.transcript_text, account_id: accountId, existing_memo: existing } }];

const raw = $input.first().json.choices[0].message.content;
const clean = raw.replace(/```json|```/g, '').trim();
const start = clean.indexOf('{');
const end = clean.lastIndexOf('}') + 1;
const result = JSON.parse(clean.slice(start, end));
result.updated_memo.version = 'v2';
result.updated_memo.updated_at = new Date().toISOString();
return [{ json: { ...result, account_id: $('load-v1-memo').first().json.account_id } }];

const data = $input.first().json;
const fs = require('fs');
const path = require('path');
const accountId = data.account_id;
const v2dir = path.join('/data/outputs/accounts', accountId, 'v2');
fs.mkdirSync(v2dir, { recursive: true });
fs.writeFileSync(path.join(v2dir, 'account_memo.json'), JSON.stringify(data.updated_memo, null, 2));
const changelog = { account_id: accountId, from: 'v1', to: 'v2', updated_at: new Date().toISOString(), changes: data.changelog };
fs.writeFileSync(path.join(v2dir, 'changelog.json'), JSON.stringify(changelog, null, 2));
return [{ json: { account_id: accountId, changes: data.changelog.length, status: 'v2_saved' } }];
